import type { DevProject, Phase, Spec, PRD, ConversationReference, ScopeType } from "./types";

class StateStore {
  private data = new Map<string, any>();

  generateId(): string {
    return crypto.randomUUID();
  }

  // Projects
  createProject(data: Omit<DevProject, "id" | "createdAt" | "updatedAt">): DevProject {
    const now = new Date().toISOString();
    const project: DevProject = { id: this.generateId(), ...data, createdAt: now, updatedAt: now };
    this.data.set(`project:${project.id}`, project);
    return project;
  }

  getProject(id: string): DevProject | null {
    return this.data.get(`project:${id}`) ?? null;
  }

  updateProject(id: string, data: Partial<DevProject>): DevProject | null {
    const existing = this.getProject(id);
    if (!existing) return null;
    const updated: DevProject = { ...existing, ...data, id, updatedAt: new Date().toISOString() };
    this.data.set(`project:${id}`, updated);
    return updated;
  }

  deleteProject(id: string): void {
    this.data.delete(`project:${id}`);
  }

  listProjects(): DevProject[] {
    const projects: DevProject[] = [];
    for (const [key, value] of this.data) {
      if (key.startsWith("project:")) projects.push(value);
    }
    return projects;
  }

  // Phases
  createPhase(data: Omit<Phase, "id" | "createdAt" | "updatedAt">): Phase {
    const now = new Date().toISOString();
    const phase: Phase = { id: this.generateId(), ...data, createdAt: now, updatedAt: now };
    this.data.set(`phase:${phase.id}`, phase);
    return phase;
  }

  getPhase(id: string): Phase | null {
    return this.data.get(`phase:${id}`) ?? null;
  }

  getPhasesByProject(projectId: string): Phase[] {
    const phases: Phase[] = [];
    for (const [key, value] of this.data) {
      if (key.startsWith("phase:") && value.projectId === projectId) phases.push(value);
    }
    return phases.sort((a, b) => a.sortOrder - b.sortOrder);
  }

  updatePhase(id: string, data: Partial<Phase>): Phase | null {
    const existing = this.getPhase(id);
    if (!existing) return null;
    const updated: Phase = { ...existing, ...data, id, updatedAt: new Date().toISOString() };
    this.data.set(`phase:${id}`, updated);
    return updated;
  }

  deletePhase(id: string): void {
    this.data.delete(`phase:${id}`);
  }

  reorderPhases(projectId: string, phaseIds: string[]): void {
    phaseIds.forEach((id, index) => {
      const phase = this.getPhase(id);
      if (phase && phase.projectId === projectId) {
        this.data.set(`phase:${id}`, { ...phase, sortOrder: index, updatedAt: new Date().toISOString() });
      }
    });
  }

  // Specs
  createSpec(data: Omit<Spec, "id">): Spec {
    const spec: Spec = { id: this.generateId(), ...data };
    this.data.set(`spec:${spec.id}`, spec);
    return spec;
  }

  getSpecByPhase(phaseId: string): Spec | null {
    for (const [key, value] of this.data) {
      if (key.startsWith("spec:") && value.phaseId === phaseId) return value;
    }
    return null;
  }

  updateSpec(id: string, data: Partial<Spec>): Spec | null {
    const existing = this.data.get(`spec:${id}`);
    if (!existing) return null;
    const updated: Spec = { ...existing, ...data, id };
    this.data.set(`spec:${id}`, updated);
    return updated;
  }

  // PRDs
  createPRD(data: Omit<PRD, "id">): PRD {
    const prd: PRD = { id: this.generateId(), ...data };
    this.data.set(`prd:${prd.id}`, prd);
    return prd;
  }

  getPRDByPhase(phaseId: string): PRD | null {
    for (const [key, value] of this.data) {
      if (key.startsWith("prd:") && value.phaseId === phaseId) return value;
    }
    return null;
  }

  updatePRD(id: string, data: Partial<PRD>): PRD | null {
    const existing = this.data.get(`prd:${id}`);
    if (!existing) return null;
    const updated: PRD = { ...existing, ...data, id };
    this.data.set(`prd:${id}`, updated);
    return updated;
  }

  // Conversation References
  createConversationRef(data: Omit<ConversationReference, "id">): ConversationReference {
    const ref: ConversationReference = { id: this.generateId(), ...data };
    this.data.set(`convref:${ref.id}`, ref);
    return ref;
  }

  getConversationRefs(scopeType: ScopeType, scopeId: string): ConversationReference[] {
    const refs: ConversationReference[] = [];
    for (const [key, value] of this.data) {
      if (key.startsWith("convref:") && value.scopeType === scopeType && value.scopeId === scopeId) {
        refs.push(value);
      }
    }
    return refs;
  }

  updateConversationRef(id: string, data: Partial<ConversationReference>): ConversationReference | null {
    const existing = this.data.get(`convref:${id}`);
    if (!existing) return null;
    const updated: ConversationReference = { ...existing, ...data, id };
    this.data.set(`convref:${id}`, updated);
    return updated;
  }

  deleteConversationRef(id: string): void {
    this.data.delete(`convref:${id}`);
  }
}

export const store = new StateStore();

